// Extraer datos del webhook de Crisp
const body = $input.first().json.body || $input.first().json;

// Crisp envia: event, data.content, data.session_id, data.website_id
const event = body.event || '';
const data = body.data || {};

// Solo procesar mensajes del usuario (no del operador)
if (data.from === 'operator' || data.origin === 'chat' && data.from !== 'user') {
  return []; // No procesar mensajes propios
}

const sessionId = data.session_id || '';
const websiteId = data.website_id || '';
const mensaje = data.content || '';
const timestamp = data.timestamp || Date.now();

// Extraer session data (pagina_origen, destino, velero, modelo)
const sessionData = data.data || {};
const paginaOrigen = sessionData.pagina_origen || 'desconocida';
const destino = sessionData.destino || '';
const velero = sessionData.velero || '';
const modelo = sessionData.modelo || '';

return [{
  json: {
    sessionId,
    websiteId,
    mensaje,
    paginaOrigen,
    destino,
    velero,
    modelo,
    timestamp
  }
}];

const agentes = [
  { nombre: 'Laura', genero: 'femenino', rol: 'operadora', auto: 'en femenino (operadora, encantada, atenta)' },
  { nombre: 'Alberto', genero: 'masculino', rol: 'operador', auto: 'en masculino (operador, encantado, atento)' },
  { nombre: 'Marina', genero: 'femenino', rol: 'operadora', auto: 'en femenino (operadora, encantada, atenta)' }
];

// Asignar agente aleatorio
const agente = agentes[Math.floor(Math.random() * agentes.length)];

// Otros agentes para el prompt
const otros = agentes
  .filter(a => a.nombre !== agente.nombre)
  .map(a => `${a.nombre} (companer${a.genero === 'masculino' ? 'o' : 'a'})`)
  .join(' y ');

const input = $input.first().json;

// Saludo contextual segun pagina
let contextoExtra = '';
const p = input.paginaOrigen;
if (p.includes('/veleros/masti')) contextoExtra = 'El cliente esta mirando el velero MASTI (Mastracchio 24.5).';
else if (p.includes('/veleros/brama')) contextoExtra = 'El cliente esta mirando el velero BRAMA (Bramador 24).';
else if (p.includes('/stock') || p.includes('/veleros-en-venta')) contextoExtra = 'El cliente esta viendo el catalogo de veleros en venta.';
else if (p.includes('/destinos') || p.includes('/travesias')) contextoExtra = 'El cliente esta interesado en travesias.';
else if (p.includes('/escuela')) contextoExtra = 'El cliente esta interesado en la escuela de navegacion.';
else if (p.includes('/servicios')) contextoExtra = 'El cliente consulta por servicios tecnicos.';
if (input.velero) contextoExtra += ` Velero de interes: ${input.velero}.`;
if (input.destino) contextoExtra += ` Destino de interes: ${input.destino}.`;

const systemPrompt = `Sos ${agente.nombre}, ${agente.rol} en ENBA — Espacio Nautico Buenos Aires.

Tu genero es ${agente.genero}. Referite a vos ${agente.auto} siempre.

ENBA es un espacio nautico integral en Puerto Norte, Buenos Aires, frente al Aeroparque.
Ofrecemos: travesias en velero, escuela de navegacion (timonel y patron), compra-venta-alquiler de embarcaciones, y servicio tecnico a embarcaciones.

REGLAS CRITICAS:
- Hablas en espanol rioplatense (voseo: "vos", "tenes", "queres", "contame").
- Sos calido/a, profesional, cercano/a. NO SOS UN BOT. Sos una persona real del equipo de ENBA.
- Mensajes CORTOS. Maximo 2-3 oraciones por respuesta. Como un WhatsApp entre personas.
- NUNCA listas los servicios de ENBA al saludar. Esperas a que el cliente pregunte.
- NUNCA das precios. Decis: "Te paso la info por WhatsApp" y derivas a wa.me/5491149915143
- NUNCA confirmas fechas o disponibilidad sin verificar. Decis "dejame chequear con el equipo".
- NUNCA decis "Puerto Madero". Es "Puerto Norte, frente al Aeroparque".
- Maximo 1-2 emojis por mensaje (no mas).
- Si no podes resolver algo, derivas a WhatsApp: wa.me/5491149915143
- Si te preguntan si sos un bot, decis: "Soy un asistente virtual de ENBA, pero si preferis hablar con alguien del equipo te conecto enseguida por WhatsApp."
- NUNCA uses lenguaje de chatbot como "Claro que si!", "Con mucho gusto!", "Estoy aqui para ayudarte!". Habla como una persona normal.
- Usa contracciones y lenguaje casual: "dale", "genial", "joya", "barbaro", "de una".
- A veces responde solo con una frase corta. No siempre tiene que ser un parrafo.
- Podes usar "jaja" o "ja" cuando sea natural.

CONTEXTO DE ESTA CONVERSACION:
- Pagina de origen: ${input.paginaOrigen}
${contextoExtra ? '- ' + contextoExtra : ''}

Tus companeros de equipo son: ${otros}.
Si el cliente menciona que hablo con alguno/a, reconocelo/a como tu companero/a.`;

return [{
  json: {
    ...input,
    agente: agente.nombre,
    systemPrompt
  }
}];

const response = $input.first().json;
const respuesta = response.content?.[0]?.text || 'Perdon, tuve un problema. Escribinos por WhatsApp: wa.me/5491149915143';

// Obtener datos del nodo anterior (Asignar Agente)
const agentData = $('Asignar Agente + System Prompt').first().json;

return [{
  json: {
    respuesta,
    sessionId: agentData.sessionId,
    websiteId: agentData.websiteId,
    agente: agentData.agente
  }
}];
